import{_ as s,c as i,o as t,ag as e}from"./chunks/framework.BDwTZuFy.js";const u=JSON.parse('{"title":"Actions and defaults","description":"","frontmatter":{},"headers":[],"relativePath":"docs/actions-and-defaults.md","filePath":"docs/actions-and-defaults.md"}'),n={name:"docs/actions-and-defaults.md"};function o(r,a,l,h,d,p){return t(),i("div",null,a[0]||(a[0]=[e(`<h1 id="actions-and-defaults" tabindex="-1">Actions and defaults <a class="header-anchor" href="#actions-and-defaults" aria-label="Permalink to &quot;Actions and defaults&quot;">​</a></h1><p>Compas will do a few things automatically for you when it is running. These are called integrations. Some of them only run once configured. Others are enabled by default.</p><p>By default, Compas will watch your package.json files and determine if it needs to reinstall your dependencies. This way your local environment always matches the required dependency versions.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Compas is configurable via a JSON file at <code>config/compas.json</code>. An empty config file is automatically created in your project when you run Compas. In this config file, you can configure custom actions. These actions will be available when Compas is running and can be executed via the configured shortcuts.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	&quot;actions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">		{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">			&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Lint&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">			&quot;shortcut&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;L&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">			&quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npm&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;run&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;lint&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">		}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Now when you press &#39;L&#39; when Compas is running, it will run the defined command and return back to the menu. When a process is running, you can restart it with &#39;R&#39; or kill the running process by pressing &#39;K&#39;.</p><p>The configuration file is automatically reloaded on changes, assuming that the syntax is correct. Allowing you to iterate on it and expand your <a href="/docs/workspaces.html">workspace</a>.</p><h2 id="inferred-actions" tabindex="-1">Inferred actions <a class="header-anchor" href="#inferred-actions" aria-label="Permalink to &quot;Inferred actions&quot;">​</a></h2><p>Compas tries to give you a good experience without any configuration. This is why Compas automatically infers some standard actions based on your project setup.</p><p>These inferred actions are only added when no action with the same or similar name is defined. For example, &#39;Lint&#39; is only added if both &#39;Lint&#39; and &#39;Format&#39; are not configured.</p><ul><li>&#39;Dev&#39; is automatically populated from the package.json scripts.</li><li>&#39;Lint&#39; defaults to the &#39;format&#39; script defined in your package.json OR the &#39;lint&#39; script defined in your package.json OR to <code>compas lint</code> if the <code>@compas/cli</code> package is installed.</li><li>&#39;Test&#39; is based on the &#39;test&#39; script in your package.json OR to <code>compas test</code> if the <code>@compas/cli</code> package is installed.</li></ul><h2 id="other-integrations" tabindex="-1">Other integrations <a class="header-anchor" href="#other-integrations" aria-label="Permalink to &quot;Other integrations&quot;">​</a></h2><p>Compas supports much more. Like automatically starting Docker containers for services that your development environment needs, or running the code generators automatically on changes (not yet implemented). For more information, checkout the <a href="/docs/integrations/docker.html">integrations</a>.</p>`,14)]))}const k=s(n,[["render",o]]);export{u as __pageData,k as default};
